/**
 * Email notification handler — formats and dispatches email notifications
 * for order lifecycle events.
 *
 * Integrates with the EventBus-based notification architecture.
 * See ARCHITECTURE.md for rationale.
 *
 * Depends on:
 * - EventBus (event system) for receiving order lifecycle events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  from: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

export interface EmailTransport {
  send(message: EmailMessage): Promise<boolean>;
}

/**
 * Default in-memory transport that records sent emails.
 * Replace with a real SMTP/API transport in production.
 */
export class InMemoryEmailTransport implements EmailTransport {
  private sent: EmailMessage[] = [];

  async send(message: EmailMessage): Promise<boolean> {
    this.sent.push(message);
    return true;
  }

  getSentEmails(): EmailMessage[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

const STATUS_LABELS: Record<string, string> = {
  pending: 'Pending',
  confirmed: 'Confirmed',
  shipped: 'Shipped',
  delivered: 'Delivered',
  cancelled: 'Cancelled',
};

function statusLabel(status: string): string {
  return STATUS_LABELS[status] ?? status;
}

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private fromAddress = 'orders@taskflow.example.com';

  constructor(
    private eventBus: EventBus,
    private transport: EmailTransport,
  ) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    const itemRows = event.order.items
      .map((item) => `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td></tr>`)
      .join('\n');

    const itemList = event.order.items
      .map((item) => `${item.name} x${item.quantity} @ $${item.unitPrice.toFixed(2)}`)
      .join('\n');

    const htmlBody = `<h1>Order Confirmation</h1>
<p>Hi ${event.user.name},</p>
<p>Your order <strong>${event.order.id}</strong> has been placed.</p>
<table>
<tr><th>Item</th><th>Qty</th><th>Price</th></tr>
${itemRows}
</table>
<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`;

    const textBody = `Order Confirmation

Hi ${event.user.name},

Your order ${event.order.id} has been placed.

Items:
${itemList}

Total: $${event.order.total.toFixed(2)}`;

    await this.transport.send({
      to: event.user.email,
      from: this.fromAddress,
      subject: `Order Confirmation: ${event.order.id}`,
      htmlBody,
      textBody,
      sentAt: new Date(),
    });
  }

  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status change email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const previousLabel = statusLabel(event.previousStatus);
    const newLabel = statusLabel(event.newStatus);

    const statusMessages: Record<string, string> = {
      confirmed: 'Your order has been confirmed and is being prepared.',
      shipped: 'Your order has been shipped and is on its way.',
      delivered: 'Your order has been delivered. We hope you enjoy your purchase!',
      cancelled: 'Your order has been cancelled.',
    };

    const detail = statusMessages[event.newStatus] ?? `Your order status changed from ${previousLabel} to ${newLabel}.`;

    const htmlBody = `<h1>Order Status Update</h1>
<p>Your order <strong>${event.order.id}</strong> status has changed.</p>
<p><strong>${previousLabel}</strong> &rarr; <strong>${newLabel}</strong></p>
<p>${detail}</p>`;

    const textBody = `Order Status Update

Your order ${event.order.id} status has changed.

${previousLabel} -> ${newLabel}

${detail}`;

    await this.transport.send({
      to: event.order.userId,
      from: this.fromAddress,
      subject: `Order ${newLabel}: ${event.order.id}`,
      htmlBody,
      textBody,
      sentAt: new Date(),
    });
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  EmailNotificationHandler,
  InMemoryEmailTransport,
} from '../../src/notifications/email-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('EmailNotificationHandler', () => {
  let eventBus: EventBus;
  let transport: InMemoryEmailTransport;

  beforeEach(() => {
    eventBus = new EventBus();
    transport = new InMemoryEmailTransport();
    new EmailNotificationHandler(eventBus, transport);
  });

  function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
    return {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        ],
        total: 20,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
      ...overrides,
    };
  }

  function makeStatusChangedEvent(
    previousStatus: string,
    newStatus: string,
  ): OrderStatusChangedEvent {
    return {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: newStatus as OrderStatusChangedEvent['order']['status'],
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus,
      newStatus,
      timestamp: new Date(),
    };
  }

  describe('order:created emails', () => {
    it('should send confirmation email on order created', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const emails = transport.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.from).toBe('orders@taskflow.example.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.subject).toContain('order-1');
    });

    it('should include item details in HTML body', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const email = transport.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Widget');
      expect(email.htmlBody).toContain('$20.00');
      expect(email.htmlBody).toContain('Alice');
    });

    it('should include item details in text body', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const email = transport.getSentEmails()[0]!;
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('$10.00');
      expect(email.textBody).toContain('$20.00');
      expect(email.textBody).toContain('Alice');
    });

    it('should include multiple items', async () => {
      const event = makeOrderCreatedEvent({
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
      });

      await eventBus.emit(event);

      const email = transport.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Widget');
      expect(email.htmlBody).toContain('Gadget');
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('Gadget x1');
    });
  });

  describe('order:status-changed emails', () => {
    it('should send email on status change', async () => {
      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));

      const emails = transport.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('user-1');
      expect(emails[0]?.subject).toContain('Confirmed');
      expect(emails[0]?.subject).toContain('order-1');
    });

    it('should include status-specific message for confirmed', async () => {
      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));

      const email = transport.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('confirmed and is being prepared');
      expect(email.textBody).toContain('confirmed and is being prepared');
    });

    it('should include status-specific message for shipped', async () => {
      await eventBus.emit(makeStatusChangedEvent('confirmed', 'shipped'));

      const email = transport.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('shipped and is on its way');
      expect(email.textBody).toContain('shipped and is on its way');
    });

    it('should include status-specific message for delivered', async () => {
      await eventBus.emit(makeStatusChangedEvent('shipped', 'delivered'));

      const email = transport.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('delivered');
      expect(email.textBody).toContain('delivered');
    });

    it('should include status-specific message for cancelled', async () => {
      await eventBus.emit(makeStatusChangedEvent('pending', 'cancelled'));

      const email = transport.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('cancelled');
      expect(email.textBody).toContain('cancelled');
    });

    it('should include previous and new status labels', async () => {
      await eventBus.emit(makeStatusChangedEvent('confirmed', 'shipped'));

      const email = transport.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Confirmed');
      expect(email.htmlBody).toContain('Shipped');
      expect(email.textBody).toContain('Confirmed');
