    });

    it('should handle multiple status changes in sequence', async () => {
      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
      await eventBus.emit(makeStatusChangedEvent('confirmed', 'shipped'));
      await eventBus.emit(makeStatusChangedEvent('shipped', 'delivered'));

      const emails = transport.getSentEmails();
      expect(emails).toHaveLength(3);
      expect(emails[0]?.subject).toContain('Confirmed');
      expect(emails[1]?.subject).toContain('Shipped');
      expect(emails[2]?.subject).toContain('Delivered');
    });
  });

  describe('transport', () => {
    it('should clear sent emails', async () => {
      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
      expect(transport.getSentEmails()).toHaveLength(1);

      transport.clear();
      expect(transport.getSentEmails()).toHaveLength(0);
    });

    it('should set sentAt timestamp on emails', async () => {
      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));

      const email = transport.getSentEmails()[0]!;
      expect(email.sentAt).toBeInstanceOf(Date);
    });
  });
});
